static common_chat_params common_chat_params_init_mistral_instruct_v3(
    const common_chat_template &          tmpl,
    const autoparser::generation_params & inputs) {
    common_chat_params data;

    std::string system_prompt;
    std::string prompt;
    bool        first_user = true;

    for (const auto & msg : inputs.messages) {
        auto role    = msg.value("role", "");
        auto content = msg.value("content", "");

        if (role == "system") {
            system_prompt = content;
        } else if (role == "user") {
            if (first_user) {
                prompt += "<s>[INST] ";
                if (!system_prompt.empty()) {
                    prompt += system_prompt + "\n";
                }
                prompt += content + " [/INST]";
                first_user = false;
            } else {
                prompt += "[INST] " + content + " [/INST]";
            }
        } else if (role == "assistant") {
            prompt += " " + content + "</s>";
        }
    }

    data.prompt = prompt;
    data.format = COMMON_CHAT_FORMAT_CONTENT_ONLY;

    return data;
}

static json common_chat_extra_context() {
    json ctx = json::object();
    std::chrono::system_clock::time_point now = std::chrono::system_clock::now();
    std::string datetime_str = format_time(now, "%b %d %Y");
    std::string date_str = format_time(now, "%d %b %Y");
    ctx["datetime"] = datetime_str;
    ctx["date_string"] = date_str;
    return ctx;
}

